// ─────────────────────────────────────────────────────────────────
// Extrai e sanitiza os IDs recebidos no body do POST
// Aceita: { ids: ["123", "456"] }
// typeVersion 2 do Webhook coloca o body diretamente em $json
// typeVersion 1 coloca em $json.body
// ─────────────────────────────────────────────────────────────────
const raw = $input.first().json;
const ids = raw.ids ?? raw.body?.ids ?? [];

if (!Array.isArray(ids) || ids.length === 0) {
  throw new Error('Payload inválido. Envie: { "ids": ["id1", "id2"] }');
}

// Sanitiza: remove tudo que não seja alfanumérico, hífen, underscore ou ponto
const safe = ids
  .map(id => String(id).replace(/[^\w.-]/g, ''))
  .filter(Boolean);

if (!safe.length) {
  throw new Error('Nenhum ID válido após sanitização.');
}

// Formata para cláusula SQL IN: 'id1','id2','id3'
const idsForSql = safe.map(id => `'${id}'`).join(',');

return [{ json: { idsForSql, totalIds: safe.length } }];

// ─────────────────────────────────────────────────────────────────
// Formata cada produto e agrega tudo num único item
// para que o Respond to Webhook retorne um JSON array limpo
// ─────────────────────────────────────────────────────────────────
const produtos = $input.all().map(item => {
  const raw = item.json;

  // CARACTERISTICAS vem do PostgreSQL como JSONB array: [{index, value}]
  // Mantemos como array — o frontend já sabe normalizar
  let carac = raw.CARACTERISTICAS ?? [];
  if (typeof carac === 'string') {
    try { carac = JSON.parse(carac); } catch { carac = []; }
  }

  return {
    ID:             String(raw.ID ?? ''),
    TITULO:         raw.TITULO ?? '',
    DESCRICAO:      raw.DESCRICAO ?? '',
    CARACTERISTICAS: carac
  };
});

// Retorna como um único item com a chave "products"
// O frontend aceita { products: [...] } ou array direto
return [{ json: { products: produtos } }];
